using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++)
        cin >> nums[i];
    int maxSum = 0;
    vector<int> lastOccurrence(n);
    for (int i = 0; i < n; i++)
        lastOccurrence[i] = i;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (nums[i] == nums[j])
                lastOccurrence[i] = max(lastOccurrence[i], j);
        }
    }
    int maxLength = 0;
    for (int i = 0; i < n; i++) {
        maxLength = max(maxLength, lastOccurrence[i] - i);
    }
    maxSum -= maxLength;
    cout << maxSum << endl;
    return 0;
}
